package com.xda.sa2ration.lut;
import java.util.Arrays;
public final class Lut1D {public final double[] red,green,blue;public Lut1D(double[]red,double[]green,double[]blue){if(red==null||green==null||blue==null||red.length<2||red.length!=green.length||red.length!=blue.length)throw new IllegalArgumentException("Canais LUT incompatíveis");this.red=validate(red);this.green=validate(green);this.blue=validate(blue);}public int size(){return red.length;}public static Lut1D linear(int size){return gamma(size,1,1,1);}public static Lut1D gamma(int size,double r,double g,double b){if(size<2||!validGamma(r)||!validGamma(g)||!validGamma(b))throw new IllegalArgumentException("Gama inválida");return new Lut1D(channel(size,r),channel(size,g),channel(size,b));}private static boolean validGamma(double v){return Double.isFinite(v)&&v>0;}private static double[]channel(int size,double gamma){double[]out=new double[size];for(int i=0;i<size;i++)out[i]=Math.pow(i/(double)(size-1),1.0/gamma);return out;}private static double[]validate(double[]input){double[]out=Arrays.copyOf(input,input.length);for(double v:out)if(!Double.isFinite(v))throw new IllegalArgumentException("LUT contém NaN/infinito");return out;}}
